import re
from typing import Any


class MSLValue:
    TENSOR_REGEX = re.compile(r"tensor<\d+x(.+)>")
    PTR_REGEX = re.compile(r"!tt\.ptr<(\w+)>")

    def __init__(
        self, name: str | None, val_type: str, val: Any, id: int | None, made_by_make_range=False, made_by_splat=False
    ):
        # if name and id are None, this is just a temp var and not refereced
        # e.g. start and end of make_range
        self.name = name
        self.val_type = val_type
        self.val = val
        self.id = id

        # flags for values generated by tt_make_range and tt_splat to further modify their type when emitting MSL code
        self.made_by_make_range = made_by_make_range
        self.made_by_splat = made_by_splat

    def is_ptr(self, type_str: str) -> bool:
        return bool(re.match(self.PTR_REGEX, type_str))

    def get_msl_type(self) -> str:
        if self.made_by_make_range or self.made_by_splat:
            raise NotImplementedError("Handling for values made by tt_make_range and tt_splat is not implemented yet")
        elif bool(re.match(r"tensor<", self.val_type)):
            print(f"Extracting element type from tensor type {self.val_type}")
            # extract type from tensor type, e.g. tensor<1024xi32> -> i32
            element_type = re.search(self.TENSOR_REGEX, self.val_type).group(1)

            if element_type not in TTIR_TO_MSL_TYPE and self.is_ptr(element_type):
                # handle case where element type is pointer type, e.g. tensor<1024x!tt.ptr<i32>> -> !tt.ptr<i32> -> device int *
                element_type = re.search(self.PTR_REGEX, element_type).group(1)
                return f"device {TTIR_TO_MSL_TYPE[element_type]} *"

            return TTIR_TO_MSL_TYPE[element_type]
        elif self.is_ptr(self.val_type):
            # extract type from pointer type, e.g. !tt.ptr<i32> -> i32
            element_type = re.search(self.PTR_REGEX, self.val_type).group(1)
            return f"device {TTIR_TO_MSL_TYPE[element_type]} *"
        else:
            return TTIR_TO_MSL_TYPE[self.val_type]


class MSLOp:
    def __init__(self, op_type: str, operands: list[MSLValue], results: list[MSLValue], predicate: str | None = None):
        self.op_type = op_type
        self.operands = operands
        self.results = results
        self.predicate = predicate

    def __repr__(self):
        operand_str = ", ".join([f"{var.val_type} {var.name if var.name else var.val}" for var in self.operands])
        result_str = ", ".join([f"{var.val_type} {var.name if var.name else '<temp>'}" for var in self.results])
        predicate_str = f" if {self.predicate}" if self.predicate else ""
        return f"{self.op_type}({operand_str}) -> ({result_str}){predicate_str}"


PREDICATE_VALS = {
    0: "eq",
    1: "ne",
    2: "slt",
    3: "sle",
    4: "sgt",
    5: "sge",
    6: "ult",
    7: "ule",
    8: "ugt",
    9: "uge",
}

PREDICATE_VAL_SYMBOL = {
    "eq": "==",
    "ne": "!=",
    "slt": "<",
    "sle": "<=",
    "sgt": ">",
    "sge": ">=",
    "ult": "<",
    "ule": "<=",
    "ugt": ">",
    "uge": ">=",
}


TTIR_TO_MSL_TYPE = {
    "i32": "int",
    "f32": "float",
    "i1": "bool",
    # TODO add more type mapping as needed
}


class MSLKernel:
    def __init__(self, mod):
        self.mod = mod
        self.orig_ops = []
        self.msl_ops: list[MSLOp] = []
        self.id_to_mslvalue = {}  # map value id to MSLValue
        self.var_index = 0  # for generating unique variable names
        self.kernel_args = []
        self.name = mod.get_entry_func_name()

    def request_new_var_name(self) -> str:
        name = f"v{self.var_index}"
        self.var_index += 1
        return name

    def _init_orig_ops(self) -> list:
        self.mod.walk(lambda op: self.orig_ops.append(op))
        return self.orig_ops

    def _init_msl_ops(self) -> list[MSLOp]:
        # process function to extract arguments first, skip tt.func and builtin.module later
        self.initial_process_func()

        # walk module
        if len(self.orig_ops) == 0:
            # op walk has not been done, do it now
            self._init_orig_ops()
        ops = self.orig_ops
        for i, op in enumerate(ops):
            msl_op = self.process_op(op)
            if msl_op is not None:
                self.msl_ops.append(msl_op)

        return self.msl_ops

    def initial_process_func(self):
        # extract function name and attributes
        mod = self.mod
        func = mod.get_function(self.name)
        num_args = func.get_num_args()
        for i in range(num_args):
            arg = func.args(i)
            arg_type = str(arg.get_type())
            arg_id = arg.id()
            arg_val = MSLValue(f"arg_{i}", arg_type, None, arg_id)
            self.id_to_mslvalue[arg_id] = arg_val
            self.kernel_args.append(arg_val)

        print(
            f"Processed function {self.name} with {num_args} arguments: {[str(func.args(i).get_type()) for i in range(num_args)]}"
        )

    def process_op(self, op) -> MSLOp:
        name = op.get_name()
        method_name = f"process_{name}".replace(".", "_")
        handler = getattr(self, method_name, self.process_unknown_op)
        print("Processing op:", name)
        msl_op = handler(op)
        print(f"Processed op: {msl_op}")

        return msl_op

    def process_arith_constant(self, op) -> MSLOp:
        op_type = "arith.constant"
        assert op.get_num_operands() == 0
        # just put constant value in MSL operands
        operands = []
        # constant value
        const_val = op.get_int_attr("value")
        operands.append(MSLValue(None, "i32", const_val, None))

        # result
        assert op.get_num_results() == 1
        result_type = str(op.get_result(0).get_type())
        result_id = op.get_result(0).id()
        result_val = MSLValue(f"c{const_val}_{result_type}", result_type, const_val, result_id)
        self.id_to_mslvalue[result_id] = result_val
        return MSLOp(op_type, operands, [result_val])

    def process_tt_get_program_id(self, op) -> MSLOp:
        op_type = "tt.get_program_id"
        axis = op.get_int_attr("axis")
        # treat axis as operand
        operands = [MSLValue(None, "i32", axis, None)]

        assert op.get_num_results() == 1
        result_type = str(op.get_result(0).get_type())
        result_id = op.get_result(0).id()
        result_val = MSLValue(self.request_new_var_name(), result_type, None, result_id)
        self.id_to_mslvalue[result_id] = result_val
        return MSLOp(op_type, operands, [result_val])

    def process_arith_muli(self, op) -> MSLOp:
        op_type = "arith.muli"
        return self.generic_process_fn(op, op_type, num_operands=2, num_results=1)

    def process_tt_make_range(self, op) -> MSLOp:
        """
        Other vars that use result of this op must calculate index in MSL during MSL emission
        """
        op_type = "tt_make_range"
        assert op.get_num_operands() == 0
        operands = []

        # start operand
        start_operand_val = op.get_int_attr("start")
        operands.append(MSLValue(None, "i32", start_operand_val, None))

        # end operand
        end_operand_val = op.get_int_attr("end")
        operands.append(MSLValue(None, "i32", end_operand_val, None))

        # result
        assert op.get_num_results() == 1
        result = op.get_result(0)
        result_type = str(result.get_type())
        result_id = result.id()
        result_val = MSLValue(self.request_new_var_name(), result_type, None, result_id, made_by_make_range=True)
        self.id_to_mslvalue[result_id] = result_val

        return MSLOp(op_type, operands, [result_val])

    def process_tt_splat(self, op) -> MSLOp:
        """
        Other vars that use result of this op can just use original variable in MSL during MSL emission
        """
        op_type = "tt_splat"
        assert op.get_num_operands() == 1
        operand = op.get_operand(0)
        operand_id = operand.id()
        if operand_id in self.id_to_mslvalue:
            operand_val = self.id_to_mslvalue[operand_id]
        else:
            raise ValueError(f"Operand with id {operand_id} not found in id_to_mslvalue mapping")
        operands = [operand_val]

        # result
        assert op.get_num_results() == 1
        result = op.get_result(0)
        result_type = str(result.get_type())
        result_id = result.id()
        result_val = MSLValue(self.request_new_var_name(), result_type, None, result_id, made_by_splat=True)
        self.id_to_mslvalue[result_id] = result_val

        return MSLOp(op_type, operands, [result_val])

    def process_arith_addi(self, op) -> MSLOp:
        op_type = "arith.addi"
        return self.generic_process_fn(op, op_type, num_operands=2, num_results=1)

    def process_arith_cmpi(self, op) -> MSLOp:
        op_type = "arith.cmpi"

        msl_op = self.generic_process_fn(op, op_type, num_operands=2, num_results=1)
        msl_op.predicate = PREDICATE_VALS[op.get_int_attr("predicate")]  # e.g. "eq", "ne", "slt", etc.
        return msl_op

    def process_tt_addptr(self, op) -> MSLOp:
        op_type = "tt.addptr"
        return self.generic_process_fn(op, op_type, num_operands=2, num_results=1)

    def process_tt_load(self, op) -> MSLOp:
        # second operand is mask, to be handled in MSL emission
        op_type = "tt.load"
        return self.generic_process_fn(op, op_type, num_operands=2, num_results=1)

    def process_arith_addf(self, op) -> MSLOp:
        op_type = "arith.addf"
        return self.generic_process_fn(op, op_type, num_operands=2, num_results=1)

    def process_tt_store(self, op) -> MSLOp:
        # second operand is mask, to be handled in MSL emission
        op_type = "tt.store"
        return self.generic_process_fn(op, op_type, num_operands=3, num_results=0)

    def generic_process_fn(self, op, op_type, num_operands: int, num_results: int) -> MSLOp:
        assert op.get_num_operands() == num_operands
        operands = []
        for i in range(op.get_num_operands()):
            operand = op.get_operand(i)
            operand_id = operand.id()
            # TODO should only operate on defined variables?
            if operand_id in self.id_to_mslvalue:
                operand_val = self.id_to_mslvalue[operand_id]
            else:
                raise ValueError(f"Operand with id {operand_id} not found in id_to_mslvalue mapping")
            operands.append(operand_val)
        assert op.get_num_results() == num_results
        results = []
        for i in range(num_results):
            result = op.get_result(i)
            result_type = str(result.get_type())
            result_id = result.id()
            result_val = MSLValue(self.request_new_var_name(), result_type, None, result_id)
            self.id_to_mslvalue[result_id] = result_val
            results.append(result_val)
        return MSLOp(op_type, operands, results)

    def process_tt_return(self, op) -> MSLOp:
        op_type = "tt.return"
        assert op.get_num_operands() == 0
        operands = []
        assert op.get_num_results() == 0
        results = []
        return MSLOp(op_type, operands, results)

    def process_tt_func(self, op) -> MSLOp:
        pass

    def process_builtin_module(self, op) -> MSLOp:
        pass

    def process_unknown_op(self, op) -> MSLOp:
        raise NotImplementedError(f"Processing for op {op.get_name()} is not implemented yet")

    def generate_msl_code(self) -> str:
        self._init_msl_ops()
        msl_lines = []
        msl_lines.append(self.get_msl_function_signature())
        msl_lines.append("{")
        for msl_op in self.msl_ops:
            print(f"Generating MSL code for op: {msl_op}")
            msl_line = self.get_msl_line(msl_op)
            if isinstance(msl_line, list):
                # TODO replace with space?
                msl_lines.extend([f"\t{line}" for line in msl_line])
            else:
                msl_lines.append(f"\t{msl_line}")
        msl_lines.append("}")
        return "\n".join(msl_lines)

    def get_msl_line(self, msl_op: MSLOp) -> str:
        method_name = f"get_msl_{msl_op.op_type.replace('.', '_')}"
        handler = getattr(self, method_name, self.get_msl_unknown_op)
        msl_line = handler(msl_op)
        return msl_line

    def get_msl_function_signature(self) -> str:
        def get_func_signature_arg_type(arg: MSLValue) -> str:
            if not arg.is_ptr(arg.val_type):
                # TODO need to handle case where argument is not a scalar?
                return f"device {arg.get_msl_type()} &"  # pass by reference for non-pointer types

            # get_msl_type already adds "device" and "*" for pointer types
            return arg.get_msl_type()

        arg_str = ", ".join([f"{get_func_signature_arg_type(arg)} {arg.name}" for arg in self.kernel_args])
        # TODO handle multiple dimensions
        signature = f"kernel void {self.name}({arg_str}, uint thread_threadgroup_idx [[thread_position_in_threadgroup]], uint threadgroup_grid_idx [[threadgroup_position_in_grid]])"
        return signature

    # methods to get MSL string for specific op
    def get_msl_arith_constant(self, msl_op: MSLOp) -> str:
        const_type = msl_op.operands[0].get_msl_type()
        const_val = msl_op.operands[0].val
        const_name = msl_op.results[0].name
        msl_line = f"const {const_type} {const_name} = {const_val};"

        return msl_line

    def get_msl_tt_get_program_id(self, msl_op: MSLOp) -> str:
        var_type = msl_op.results[0].get_msl_type()
        var_name = msl_op.results[0].name
        # TODO handle multiple dimension
        msl_line = f"{var_type} {var_name} = threadgroup_grid_idx;"  # TODO make sure threadgroup_grid_idx is in MSL function signature
        return msl_line

    def generic_msl_arith(self, msl_op: MSLOp, operator: str) -> str:
        operand_str = f"{msl_op.operands[0].name} {operator} {msl_op.operands[1].name}"
        result_type = msl_op.results[0].get_msl_type()
        result_str = msl_op.results[0].name
        msl_line = f"{result_type} {result_str} = {operand_str};"
        return msl_line

    def get_msl_arith_muli(self, msl_op: MSLOp) -> str:
        return self.generic_msl_arith(msl_op, "*")

    def get_msl_tt_make_range(self, msl_op: MSLOp) -> str:
        """
        Make range is used when doing vectorized operation.
        e.g. Generating vector of offsets to calculate memory address:
        %c32_i32 = arith.constant 32 : i32 loc(#loc)
        %0 = tt.get_program_id x : i32 loc(#loc)
        %1 = arith.muli %0, %c32_i32 : i32 loc(#loc)
        %2 = tt.make_range {end = 32 : i32, start = 0 : i32} : tensor<32xi32> loc(#loc)
        %3 = tt.splat %1 : i32 -> tensor<32xi32> loc(#loc)
        %4 = arith.addi %3, %2 : tensor<32xi32> loc(#loc)

        When emitting MSL, modify from vectorized code to thread-based MSL code.
        TODO make sure to handle other use cases of make_range if there are any
        """

        start_type = msl_op.operands[0].get_msl_type()
        msl_line = f"{start_type} {msl_op.results[0].name} = thread_threadgroup_idx;"  # TODO make sure thread_threadgroup_idx is in MSL function signature
        return msl_line

    def get_msl_tt_splat(self, msl_op: MSLOp) -> str:
        # just do simple variable assignment in MSL since pointer calculation is not vectorized
        operand_type = msl_op.operands[0].get_msl_type()
        msl_line = f"{operand_type} {msl_op.results[0].name} = {msl_op.operands[0].name};"
        return msl_line

    def get_msl_arith_addi(self, msl_op: MSLOp) -> str:
        return self.generic_msl_arith(msl_op, "+")

    def get_msl_arith_cmpi(self, msl_op: MSLOp) -> str:
        operator = PREDICATE_VAL_SYMBOL[msl_op.predicate]
        return self.generic_msl_arith(msl_op, operator)

    def get_msl_tt_addptr(self, msl_op: MSLOp) -> str:
        return self.generic_msl_arith(msl_op, "+")

    def get_msl_tt_load(self, msl_op: MSLOp) -> list[str]:
        # handle mask
        mask_var = msl_op.operands[1].name
        load_var = msl_op.results[0].name
        ptr_var = msl_op.operands[0].name
        var_type = msl_op.results[0].get_msl_type()
        # first declare, then load value if mask true
        # TODO need to make sure there are no side effects if load_var is not initialized
        msl_lines = [f"{var_type} {load_var};"]
        msl_lines.append(f"if ({mask_var}) {{")
        msl_lines.append(f"    {load_var} = *{ptr_var};")
        msl_lines.append("}")
        return msl_lines

    def get_msl_arith_addf(self, msl_op: MSLOp) -> str:
        return self.generic_msl_arith(msl_op, "+")

    def get_msl_tt_store(self, msl_op: MSLOp) -> list[str]:
        # handle mask
        mask_var = msl_op.operands[2].name
        ptr_var = msl_op.operands[0].name
        value_var = msl_op.operands[1].name
        msl_lines = [f"if ({mask_var}) {{"]
        msl_lines.append(f"    *{ptr_var} = {value_var};")
        msl_lines.append("}")
        return msl_lines

    def get_msl_tt_return(self, msl_op: MSLOp) -> str:
        return "// return from function"

    def get_msl_unknown_op(self, msl_op: MSLOp) -> str:
        raise NotImplementedError(f"MSL generation for op {msl_op.op_type} is not implemented yet")
